/* Diff Review Panel Styles */

/* Theme-aware color scheme */
:root {
  /* Backgrounds */
  --diff-bg: var(--vscode-editor-background);
  --diff-gutter-bg: var(--vscode-editorGutter-background, var(--vscode-editor-background));
  --toolbar-bg: var(--vscode-editorWidget-background);
  --bg-color: var(--vscode-editor-background);

  /* Text */
  --text-color: var(--vscode-editor-foreground);
  --text-primary: var(--vscode-editor-foreground);
  --text-secondary: var(--vscode-descriptionForeground);
  --text-link: var(--vscode-textLink-foreground);

  /* Borders */
  --border-color: var(--vscode-panel-border);

  /* Diff colors */
  --diff-add-bg: var(--vscode-diffEditor-insertedTextBackground, rgba(35, 134, 54, 0.2));
  --diff-add-highlight: var(--vscode-diffEditor-insertedLineBackground, rgba(35, 134, 54, 0.3));
  --diff-del-bg: var(--vscode-diffEditor-removedTextBackground, rgba(248, 81, 73, 0.2));
  --diff-del-highlight: var(--vscode-diffEditor-removedLineBackground, rgba(248, 81, 73, 0.3));

  /* Interactive */
  --button-bg: var(--vscode-button-background);
  --button-fg: var(--vscode-button-foreground);
  --button-hover: var(--vscode-button-hoverBackground);
  --input-bg: var(--vscode-input-background);
  --input-border: var(--vscode-input-border);
  --focus-border: var(--vscode-focusBorder);

  /* Status */
  --success: var(--vscode-gitDecoration-addedResourceForeground, #3fb950);
  --warning: var(--vscode-gitDecoration-modifiedResourceForeground, #d29922);
  --error: var(--vscode-gitDecoration-deletedResourceForeground, #f85149);
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  padding: 0;
  background: var(--bg-color);
  color: var(--text-color);
  font-family: var(--vscode-font-family);
  font-size: var(--vscode-font-size);
}

#app {
  display: flex;
  flex-direction: column;
  height: 100vh;
}

/* Toolbar */
#toolbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 16px;
  background: var(--toolbar-bg);
  border-bottom: 1px solid var(--border-color);
  flex-shrink: 0;
}

.toolbar-left {
  display: flex;
  align-items: center;
  gap: 12px;
  overflow: hidden;
}

.toolbar-right {
  display: flex;
  align-items: center;
  gap: 8px;
  flex-shrink: 0;
}

#filename {
  font-weight: bold;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

#stats {
  font-size: 12px;
  color: var(--text-secondary);
  margin-left: 8px;
}

/* Stats styling */
.additions {
  color: var(--success);
  margin-right: 8px;
}

.deletions {
  color: var(--error);
}

/* Diff Container */
#diff-container {
  flex: 1;
  overflow: auto;
  padding: 16px;
}

/* Loading State */
.loading, .loading-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  color: var(--text-secondary);
  text-align: center;
  padding: 48px;
}

.spinner {
  width: 24px;
  height: 24px;
  border: 2px solid var(--border-color);
  border-top-color: var(--button-bg);
  border-radius: 50%;
  animation: spin 1s linear infinite;
  margin-bottom: 12px;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

/* Placeholder content */
#diff-container pre {
  background: var(--vscode-textBlockQuote-background);
  padding: 16px;
  border-radius: 4px;
  overflow-x: auto;
  font-family: var(--vscode-editor-font-family);
  font-size: var(--vscode-editor-font-size);
  line-height: 1.5;
  white-space: pre-wrap;
  word-break: break-word;
}

#diff-container hr {
  border: none;
  border-top: 1px solid var(--border-color);
  margin: 16px 0;
}

/* diff2html base overrides for VSCode integration */
.d2h-wrapper {
  font-family: var(--vscode-editor-font-family);
  font-size: var(--vscode-editor-font-size);
  background: var(--diff-bg) !important;
  color: var(--text-primary) !important;
}

.d2h-file-wrapper {
  border: 1px solid var(--border-color);
  border-radius: 4px;
  margin-bottom: 16px;
}

.d2h-file-header {
  background: var(--toolbar-bg) !important;
  border-bottom: 1px solid var(--border-color);
  border-color: var(--border-color) !important;
}

/* Dark theme overrides for diff2html */
.d2h-dark-color-scheme .d2h-file-header {
  background: var(--vscode-editor-background);
  border-color: var(--border-color);
}

.d2h-dark-color-scheme .d2h-code-line,
.d2h-code-line-ctn {
  background: var(--diff-bg) !important;
}

.d2h-dark-color-scheme .d2h-code-side-line {
  background: var(--vscode-editor-background);
}

.d2h-dark-color-scheme .d2h-code-linenumber,
.d2h-code-linenumber {
  background: var(--diff-gutter-bg) !important;
  color: var(--text-secondary) !important;
  border-color: var(--border-color) !important;
}

.d2h-dark-color-scheme .d2h-ins,
.d2h-ins {
  background: var(--diff-add-bg) !important;
}

.d2h-dark-color-scheme .d2h-ins .d2h-code-line-ctn,
.d2h-ins .d2h-code-line-ctn {
  background: var(--diff-add-bg) !important;
}

.d2h-ins.d2h-change {
  background: var(--diff-add-highlight) !important;
}

.d2h-dark-color-scheme .d2h-del,
.d2h-del {
  background: var(--diff-del-bg) !important;
}

.d2h-dark-color-scheme .d2h-del .d2h-code-line-ctn,
.d2h-del .d2h-code-line-ctn {
  background: var(--diff-del-bg) !important;
}

.d2h-del.d2h-change {
  background: var(--diff-del-highlight) !important;
}

.d2h-dark-color-scheme .d2h-info,
.d2h-info {
  background: var(--toolbar-bg);
  color: var(--text-secondary);
}

/* Line number hover for comment addition */
.d2h-code-linenumber:hover {
  background: var(--vscode-list-hoverBackground) !important;
}

/* High contrast mode */
.vscode-high-contrast .d2h-ins {
  border-left: 2px solid var(--success);
}

.vscode-high-contrast .d2h-del {
  border-left: 2px solid var(--error);
}

/* Theme variations */
body.dark {
  /* Dark theme overrides if needed */
}

body.light {
  /* Light theme overrides if needed */
}

/* Empty state */
.empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 48px;
  color: var(--text-secondary);
}

.empty-state .icon {
  font-size: 48px;
  margin-bottom: 16px;
  opacity: 0.5;
}

/* Error state */
.error-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 48px;
  color: var(--error);
}

.error-state details {
  margin-top: 16px;
  width: 100%;
  max-width: 800px;
}

.error-state summary {
  cursor: pointer;
  color: var(--text-link);
}

.error-state button {
  margin-top: 16px;
  padding: 8px 16px;
  background: var(--button-bg);
  color: var(--button-fg);
  border: none;
  border-radius: 4px;
  cursor: pointer;
}

/* Add comment button */
.add-comment-btn {
  position: absolute;
  left: -24px;
  top: 50%;
  transform: translateY(-50%);
  width: 20px;
  height: 20px;
  border-radius: 50%;
  border: 1px solid var(--vscode-button-border, transparent);
  background: var(--button-bg);
  color: var(--button-fg);
  cursor: pointer;
  opacity: 0;
  transition: opacity 0.15s;
  font-size: 14px;
  line-height: 1;
  padding: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 10;
}

.add-comment-btn.visible,
.add-comment-btn:focus {
  opacity: 1;
}

.add-comment-btn.active {
  opacity: 1;
  background: var(--button-hover);
}

.add-comment-btn:hover {
  background: var(--button-hover);
}

.add-comment-btn:focus {
  outline: 2px solid var(--focus-border);
  opacity: 1;
}

/* Comment input form */
.comment-input-form {
  background: var(--vscode-editor-background);
  border: 1px solid var(--input-border);
  border-radius: 6px;
  padding: 12px;
  margin: 8px 16px;
}

.comment-input-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 8px;
  font-size: 12px;
  color: var(--text-secondary);
}

.comment-input-form textarea {
  width: 100%;
  background: var(--input-bg);
  color: var(--vscode-input-foreground);
  border: 1px solid var(--input-border);
  border-radius: 4px;
  padding: 8px;
  font-family: var(--vscode-font-family);
  font-size: 13px;
  resize: vertical;
  min-height: 60px;
}

.comment-input-form textarea:focus {
  outline: 1px solid var(--focus-border);
}

.comment-input-actions {
  display: flex;
  justify-content: flex-end;
  gap: 8px;
  margin-top: 8px;
}

.comment-input-actions button {
  padding: 4px 12px;
  border-radius: 4px;
  cursor: pointer;
  font-size: 12px;
}

.cancel-btn {
  background: transparent;
  border: 1px solid var(--vscode-button-border, var(--vscode-contrastBorder, #666));
  color: var(--vscode-foreground);
}

.cancel-btn:hover {
  background: var(--vscode-list-hoverBackground);
}

.submit-btn {
  background: var(--button-bg);
  border: none;
  color: var(--button-fg);
}

.submit-btn:hover {
  background: var(--button-hover);
}

.close-btn {
  background: none;
  border: none;
  color: var(--vscode-foreground);
  cursor: pointer;
  font-size: 18px;
  padding: 0;
  line-height: 1;
}

.close-btn:hover {
  color: var(--error);
}

/* Comment thread display */
.comment-thread {
  background: var(--vscode-editor-background);
  border-left: 3px solid var(--vscode-activityBarBadge-background, #0078d4);
  margin: 8px 16px;
  padding: 8px 12px;
  border-radius: 0 6px 6px 0;
}

.comment {
  padding: 8px 0;
  border-bottom: 1px solid var(--border-color);
}

.comment:last-child {
  border-bottom: none;
}

.comment:focus {
  outline: 2px solid var(--focus-border);
  outline-offset: 2px;
}

.comment-header {
  display: flex;
  justify-content: space-between;
  font-size: 11px;
  color: var(--text-secondary);
  margin-bottom: 4px;
}

.comment-location {
  font-weight: 500;
}

.comment-body {
  font-size: 13px;
  line-height: 1.5;
  white-space: pre-wrap;
}

.comment-body.resolved {
  text-decoration: line-through;
  opacity: 0.6;
}

.comment-actions {
  margin-top: 8px;
}

.resolve-btn {
  background: transparent;
  border: 1px solid var(--vscode-button-border, var(--vscode-contrastBorder, #666));
  color: var(--vscode-foreground);
  padding: 2px 8px;
  border-radius: 4px;
  cursor: pointer;
  font-size: 11px;
}

.resolve-btn:hover {
  background: var(--vscode-list-hoverBackground);
}

.resolved-badge {
  font-size: 11px;
  color: var(--success);
}

/* Comment row in table */
.comment-row td {
  padding: 0 !important;
  background: transparent !important;
}

/* Collapsed comments */
.comment-thread.collapsed .comment-body,
.comment-thread.collapsed .comment-actions {
  display: none;
}

.comment-thread.collapsed::after {
  content: '...';
  color: var(--text-secondary);
}

/* Screen reader only */
.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

/* Reduced motion */
@media (prefers-reduced-motion: reduce) {
  .spinner {
    animation: none;
  }

  * {
    transition-duration: 0.01ms !important;
  }
}

/* Smooth scrolling */
html {
  scroll-behavior: smooth;
}

/* Selection styling */
::selection {
  background: var(--vscode-editor-selectionBackground);
}

